import{_ as t,o as a,c as n,ag as r}from"./chunks/framework.eQLvDOR_.js";const _=JSON.parse('{"title":"role-based-agent-anti-pattern","description":"","frontmatter":{"title":"role-based-agent-anti-pattern","concept":"角色划分反模式","concept_id":"role-based-agent-anti-pattern","aliases":["三省六部幻觉","Role-based Agents"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.md"],"related_concepts":["[[multi-agent-orchestrator]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/role-based-agent-anti-pattern.md","filePath":"wiki/concepts/role-based-agent-anti-pattern.md","lastUpdated":null}'),i={name:"wiki/concepts/role-based-agent-anti-pattern.md"};function o(l,e,s,c,d,g){return a(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="角色划分反模式-role-based-agent-anti-pattern" tabindex="-1">角色划分反模式 (Role-based Agent Anti-pattern) <a class="header-anchor" href="#角色划分反模式-role-based-agent-anti-pattern" aria-label="Permalink to &quot;角色划分反模式 (Role-based Agent Anti-pattern)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在多 Agent 系统设计中，将不同的 Agent 强行设定为人类社会中的“职业角色”（如产品经理、架构师、前端开发、QA），并让任务像在企业部门间流转一样的错误架构设计。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>假边界与信息损耗</strong>：大语言模型并不存在人类那样的职业壁垒，强行赋予角色标签只会让 Agent 拒绝越界思考（如“测试”忽略“架构”问题）。同时，文档在一个个角色间单向交接，导致推理链路断裂和关键上下文急剧衰减。（来源：<a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.html">[Agent_Architecture] 三省六部幻觉：为什么_虚拟公司_式多Agent架构在工程上不成立.md</a>）</li><li><strong>真正的瓶颈是推理深度</strong>：模型并发工作的瓶颈在于推理窗口与算力，而非人类注意力和学习切换的成本。多 Agent 的价值在于“并行覆盖更大的搜索空间”（比如爬取10个不同的网页），而不是“接力流水线”。</li><li><strong>工具决定能力</strong>：赋给 Agent 什么样的工具集远比打什么角色标签重要。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>永远不要问“我需要几个扮演不同职能的 Agent”，而应该问“我的任务能否被分解为多个互不相互依赖的并行流”。让一个拥有完整意图的主 Agent 利用工具，或者分叉去探索不同方案，远优于设计一条由“多角色 Agent ”构成的工厂流水线。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/multi-agent-orchestrator.html">multi-agent-orchestrator</a> — 指导如何正确拆分多重并发智能体工作的正面架构模式。</li></ul>',9)])])}const p=t(i,[["render",o]]);export{_ as __pageData,p as default};
